    92→export function animateMerges(game, matchGroups, processMergesCallback, speedMultiplier = 1) {
    93→    matchGroups.forEach((group) => {
    94→        const middlePositions = calculateMiddlePositions(game, group.tiles, group);
    95→        const outerTiles = getOuterTiles(group.tiles, middlePositions);
    96→
    97→        // Assign outer tiles to nearest middle positions for better visual flow
    98→        const assignments = assignTilesToTargets(outerTiles, middlePositions);
    99→
   100→        // Animate outer tiles sliding to their assigned middle positions
