   121→function slideGemTo(fromTile, toTile, speedMultiplier = 1) {
   122→    const fromElement = document.querySelector(`[data-row="${fromTile.row}"][data-col="${fromTile.col}"]`);
   123→    const toElement = document.querySelector(`[data-row="${toTile.row}"][data-col="${toTile.col}"]`);
   124→
   125→    if (fromElement && toElement) {
   126→        const fromRect = fromElement.getBoundingClientRect();
   127→        const toRect = toElement.getBoundingClientRect();
   128→
   129→        const deltaX = toRect.left - fromRect.left;
   130→        const deltaY = toRect.top - fromRect.top;
   131→
   132→        fromElement.style.transform = `translate(${deltaX}px, ${deltaY}px)`;
   133→        fromElement.style.transition = `transform ${0.4 * speedMultiplier}s ease-out`;
   134→        fromElement.classList.add("sliding");
   135→
   136→        // Fade out the sliding tile
   137→        setTimeout(() => {
   138→            fromElement.style.opacity = "0";
   139→        }, 300 * speedMultiplier);
   140→    }
   141→}
