   143→function getOuterTiles(allTiles, middleTiles) {
   144→    return allTiles.filter((tile) => !middleTiles.some((middle) => middle.row === tile.row && middle.col === tile.col));
   145→}
   146→
   147→// Assign each outer tile to its nearest target position based on Manhattan distance
   148→function assignTilesToTargets(outerTiles, targetPositions) {
   149→    if (targetPositions.length === 0) return [];
   150→    if (targetPositions.length === 1) {
   151→        // If only one target, all tiles go there
   152→        return outerTiles.map((tile) => ({ tile, target: targetPositions[0] }));
   153→    }
   154→
   155→    // For multiple targets, assign each tile to its nearest target
   156→    // Track how many tiles are assigned to each target for balanced distribution
   157→    const targetCounts = new Map();
   158→    targetPositions.forEach((pos) => {
   159→        targetCounts.set(`${pos.row},${pos.col}`, 0);
   160→    });
   161→
   162→    const assignments = [];
   163→
   164→    // Sort outer tiles to process them in a consistent order
   165→    const sortedOuterTiles = [...outerTiles].sort((a, b) => {
   166→        if (a.row !== b.row) return a.row - b.row;
   167→        return a.col - b.col;
   168→    });
   169→
   170→    for (const tile of sortedOuterTiles) {
   171→        // Find the nearest target position
   172→        let bestTarget = targetPositions[0];
   173→        let bestDistance = Math.abs(tile.row - bestTarget.row) + Math.abs(tile.col - bestTarget.col);
   174→
   175→        for (const target of targetPositions) {
   176→            const distance = Math.abs(tile.row - target.row) + Math.abs(tile.col - target.col);
   177→            if (distance < bestDistance) {
   178→                bestDistance = distance;
   179→                bestTarget = target;
   180→            }
   181→        }
   182→
   183→        assignments.push({ tile, target: bestTarget });
   184→        const key = `${bestTarget.row},${bestTarget.col}`;
   185→        targetCounts.set(key, targetCounts.get(key) + 1);
   186→    }
   187→
   188→    return assignments;
   189→}
