   401→export function dropGems(game) {
   402→    // Apply gravity logic (pure, no DOM)
   403→    const { movements: movedGems, newTiles: newGems } = applyGravity(game);
   404→
   405→    // Only render board if we have moves/new gems to show
   406→    // This prevents breaking ongoing animations
   407→    if (movedGems.length > 0 || newGems.length > 0) {
   408→        game.renderBoard();
   409→
   410→        // IMMEDIATELY hide new gems before they're visible
   411→        newGems.forEach((gem) => {
   412→            const element = document.querySelector(`[data-row="${gem.row}"][data-col="${gem.col}"]`);
   413→            if (element) {
   414→                element.style.opacity = "0";
   415→            }
   416→        });
   417→
   418→        // Animate only the gems that actually moved - NO DELAY for existing tiles
   419→        // Use CSS transition instead of keyframe animation for smooth drops
   420→        movedGems.forEach((gem) => {
   421→            const element = document.querySelector(`[data-row="${gem.row}"][data-col="${gem.col}"]`);
   422→            if (element) {
   423→                // Calculate how far the gem fell
   424→                const distance = (gem.row - gem.fromRow) * (element.offsetHeight + 3); // 3 is the gap
   425→
   426→                // Start from above and animate down
   427→                element.style.transform = `translateY(-${distance}px)`;
   428→                element.style.transition = "none";
