   443→            if (element) {
   444→                element.classList.add("new-gem");
   445→                element.style.animationDelay = `${index * 0.03}s`; // Faster: 30ms instead of 50ms
   446→            }
   447→        });
   448→    }
   449→
   450→    // Calculate timeout: base animation (600ms for new-gem) + longest delay
   451→    const longestDelay = newGems.length > 0 ? (newGems.length - 1) * 0.03 * 1000 : 0; // Updated to 30ms
   452→    const totalTimeout = 400 + longestDelay;
   453→
   454→    // Check for more matches after dropping
   455→    setTimeout(() => {
   456→        document.querySelectorAll(".gem").forEach((gem) => {
   457→            gem.classList.remove("falling", "new-gem");
   458→            gem.style.animationDelay = "";
   459→            gem.style.opacity = ""; // Clear inline opacity style
   460→        });
   461→
   462→        // Check if cascade was interrupted by user input
   463→        if (game.interruptCascade) {
   464→            game.interruptCascade = false;
   465→            // Resolve the animation promise to signal old cascade is done
   466→            game.animating = false;
   467→
   468→            // Execute the pending swap if it exists and moves are available
   469→            if (game.pendingSwap) {
   470→                const { row1, col1, row2, col2, tile1, tile2 } = game.pendingSwap;
   471→                game.pendingSwap = null;
   472→
   473→                // Clear preview visualization
