   475→                    gem.classList.remove("pending-preview");
   476→                });
   477→
   478→                // Check if the tiles at those positions are still the same ones that were queued
   479→                // Skip the swap if the tiles have changed during cascading
   480→                const tilesUnchanged = game.board[row1][col1] === tile1 && game.board[row2][col2] === tile2;
   481→
   482→                // Only execute swap if tiles haven't changed, player has moves remaining, and game is active
   483→                if (tilesUnchanged && game.movesUsed < game.maxMoves && game.gameActive) {
   484→                    const didSwap = trySwap(game, row1, col1, row2, col2);
   485→                    if (!!didSwap) {
   486→                        return;
   487→                    }
   488→                }
   489→            }
   490→        }
   491→
   492→        // Check for matches regardless of gameActive state to handle cascading after running out of moves
