    0% {
        transform: scale(1);
        opacity: 1;
    }
    50% {
        transform: scale(1.3);
        box-shadow: 0 0 30px rgba(156, 39, 176, 1);
    }
    100% {
        transform: scale(0);
        opacity: 0;
    }
}

