    min-height: 0;
    justify-content: center;
    display: flex;
    align-items: center;
}

.level-text {
    margin: 0;
    color: rgba(255, 255, 255, 0.5);
    font-family: Nunito;
    font-size: 32px;
    font-style: normal;
    font-weight: 900;
    line-height: normal;
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    z-index: 100;
