    align-items: center;
    justify-content: center;
}

.gem.freeswap-horizontal-tile {
    border: 3px solid var(--tile-freeswap-border);
    position: relative;
}

.gem.freeswap-horizontal-tile::after {
    content: "";
    position: absolute;
    top: -3px;
    right: -3px;
    width: 40%;
    height: 40%;
    border-radius: 35%;
    background-color: var(--tile-freeswap-badge-bg);
    background-image: url("../assets/arrow-horizontal.svg");
    background-size: 75%;
    background-position: center;
