}

.gem.teleport-tile {
    border: 3px solid var(--tile-teleport-border);
    position: relative;
}

.gem.teleport-tile::after {
    content: "🚀";
    position: absolute;
    top: -3px;
    right: -3px;
    font-size: clamp(8px, 2vw, 16px);
    width: 40%;
    height: 40%;
    border-radius: 35%;
    background-color: var(--tile-teleport-badge-bg);
    color: var(--tile-teleport-badge-color);
